  { id: 17, noticeTitle: '공지제목 17번 항목', noticeTypeCode: 'GEN', noticeTypeCodeNm: '일반', isPinned: true, isActive: 'Y', isActiveNm: '게시', viewCount: 17000, createdBy: '작성자 17번 항목', postedDate: '2024-05-17' },
