// ─────────────────── Options ────────────────────────────────────────────────────────
const noticeTypeCodeOptions = [
  { label: '전체', value: '' },
  { label: '일반', value: 'GEN' },
  { label: '시스템', value: 'SYS' },
  { label: '이벤트', value: 'EVT' },
  { label: '점검', value: 'INS' },
];

const isActiveOptions = [
  { label: '전체', value: '' },
  { label: '게시', value: 'Y' },
  { label: '미게시', value: 'N' },
];

// ─────────────────── State ──────────────────────────────────────────────────────────
const allRows = ref<RowItem[]>([...MOCK_DATA]);

const state = reactive({
  loading:     false,
  selectedRow: null as RowItem | null,
  pageSize:    20,
  page:        { first: 0, rows: 20 },
});

const searchParams = reactive({
  noticeTitle: '',
  noticeTypeCode: '',
  postedDateRangeFrom: '',
  postedDateRangeTo: '',
  isPinned: '',
  isActive: '',
});

// ─────────────────── Computed ───────────────────────────────────────────────────────
const filteredRows = computed<RowItem[]>(() => {
  let rows = allRows.value;
  if (searchParams.noticeTitle) rows = rows.filter(r => r.noticeTitle.includes(searchParams.noticeTitle));
  if (searchParams.noticeTypeCode) rows = rows.filter(r => r.noticeTypeCode === searchParams.noticeTypeCode);
  if (searchParams.postedDateRangeFrom) rows = rows.filter(r => r.postedDateRange >= searchParams.postedDateRangeFrom);
  if (searchParams.postedDateRangeTo)   rows = rows.filter(r => r.postedDateRange <= searchParams.postedDateRangeTo);
  if (searchParams.isPinned) rows = rows.filter(r => r.isPinned === searchParams.isPinned);
  if (searchParams.isActive) rows = rows.filter(r => r.isActive === searchParams.isActive);
  return rows;
});

const pagedRows = computed<RowItem[]>(() =>
  filteredRows.value.slice(state.page.first, state.page.first + state.pageSize)
);

// ─────────────────── Handlers ───────────────────────────────────────────────────────
function onSearch(): void {
  state.page        = { first: 0, rows: state.pageSize };
  state.selectedRow = null;
}

function onReset(): void {
  Object.assign(searchParams, { noticeTitle: '', noticeTypeCode: '', postedDateRangeFrom: '', postedDateRangeTo: '', isPinned: '', isActive: '' });
  onSearch();
}

function onRowSelect(event: { data: RowItem }): void {
  state.selectedRow = event.data;
}

function onPageChange(event: { first: number; rows: number }): void {
  state.page = event;
}

function onEdit(): void {
  // TODO: 수정 화면으로 이동 또는 모달 오픈
  console.log('[scaffold] onEdit →', state.selectedRow);
}

function onDelete(): void {
  if (!state.selectedRow) return;
  allRows.value     = allRows.value.filter(r => r.id !== state.selectedRow!.id);
  state.selectedRow = null;
}
</script>
